 87→export const addCommentService = async(userId, comments, postId, receiverId, parentId) => {
 88→    if(!comments || !postId || !receiverId){
 89→        throw new AppError(400, 'comments || postId || receiverId is undefined');
 90→    }
 91→
 92→    if(!userId){
 93→        throw new AppError(400, 'userId is undefined');
 94→    }
 95→    const isOwnContent = userId === receiverId;
 96→
 97→    const insertNotifPromise = supabase
 98→    .from('notifications')
 99→    .insert(
100→        {
101→            sender_id: userId,
102→            receiver_id: receiverId,
103→            journal_id: postId,
104→            read: false,
105→            type: 'comment'
106→        }
107→    )
108→
109→    const insertCommentPromise = supabase
110→    .from('comments')
111→    .insert(
112→        {
113→            comment: comments,
114→            post_id: postId,
115→            user_id: userId,
116→            parent_id: parentId || null
117→        }
118→    )
119→
120→    const [insertNotif, insertComment] = await Promise.all([
121→        isOwnContent ? Promise.resolve({error: null}) : insertNotifPromise,
122→        insertCommentPromise
123→    ])
124→
125→    const {error: errorAddComment} = insertComment;
126→    const {error: errorAddNotif} = insertNotif;
127→
128→    if(errorAddComment || errorAddNotif){
129→        console.error('supabase error while inserting comments or notifs', errorAddComment?.message || errorAddNotif?.message);
130→        throw new AppError(500, 'supabase error while inserting comments or notifs');
131→    }
132→
133→    // Non-fatal: send @mention notifications
134→    try {
135→        const mentionMatches = comments.match(/@([\w-]+)/g);
136→        if (mentionMatches && mentionMatches.length > 0) {
137→            const usernames = [...new Set(mentionMatches.map(m => m.slice(1)))].slice(0, 10);
138→
139→            const { data: mentionedUsers } = await supabase
140→                .from('users')
141→                .select('id, username')
142→                .in('username', usernames);
143→
144→            if (mentionedUsers && mentionedUsers.length > 0) {
145→                const notifs = mentionedUsers
146→                    .filter(u => u.id !== userId && u.id !== receiverId)
147→                    .map(u => ({
148→                        sender_id: userId,
149→                        receiver_id: u.id,
150→                        journal_id: postId,
151→                        type: 'mention',
152→                        read: false,
153→                    }));
154→
155→                if (notifs.length > 0) {
156→                    await supabase.from('notifications').insert(notifs);
157→                }
158→            }
159→        }
160→    } catch (mentionErr) {
161→        console.error('non-fatal: mention notification error', mentionErr?.message);
162→    }
163→
164→    return {message: 'success'};
165→}
